const items = $input.all();
const results = [];

for (const item of items) {
  let body = item.json.body;
  if (typeof body === 'string') {
    body = JSON.parse(body);
  }

  if (!body.title || !body.content) {
    throw new Error('Missing required fields: title or content');
  }

  const idempotency_key = body.idempotency_key || require('crypto').randomUUID();
  const article_id = idempotency_key;

  results.push({
    json: {
      article_id,
      created_at: new Date().toISOString(),
      title: body.title ? body.title.trim() : '',
      content: body.content ? body.content.trim() : '',
      category: body.category ? body.category.trim() : '',
      author: body.author ? body.author.trim() : '',
      published_at: body.published_at || '',
      tags_csv: Array.isArray(body.tags) ? body.tags.join(',') : (body.tags || ''),
      raw_payload: JSON.stringify(body),
      seo_status: 'pending',
      seo_requested_at: new Date().toISOString(),
      seo_processed_at: '',
      seo_error: ''
    }
  });
}

return results;
